class Solution:
    def twoCitySchedCost(self, costs):
        # Brute force: try every subset of size n going to city A.
        from itertools import combinations
        n = len(costs) // 2
        idx = range(len(costs))
        best = None
        for groupA in combinations(idx, n):
            sa = set(groupA)
            total = 0
            for i in idx:
                total += costs[i][0] if i in sa else costs[i][1]
            if best is None or total < best:
                best = total
        return best

