class Solution:
    def twoCitySchedCost(self, costs):
        costs.sort(key=lambda c: c[0] - c[1])
        n = len(costs) // 2
        total = 0
        for i, c in enumerate(costs):
            total += c[0] if i < n else c[1]
        return total

